import React, { useState, useEffect } from 'react';
import API from '../api/axios';

const BlockMaster = () => {
    const [blocks, setBlocks] = useState([]);
    const [departments, setDepartments] = useState([]);
    const [programmes, setProgrammes] = useState([]);
    const [formData, setFormData] = useState({ department: '', programme: '', blockName: '' });
    const [loading, setLoading] = useState(false);

    useEffect(() => {
        fetchBlocks();
        fetchDepartments();
    }, []);

    const fetchBlocks = async () => {
        try {
            const { data } = await API.get('/master/block');
            setBlocks(data);
        } catch (err) {
            alert('Error fetching blocks');
        }
    };

    const fetchDepartments = async () => {
        try {
            const { data } = await API.get('/master/department');
            setDepartments(data);
        } catch (err) {
            alert('Error fetching departments');
        }
    };

    const fetchProgrammes = async (deptId) => {
        try {
            const { data } = await API.get('/master/programme');
            const filtered = data.filter(p => p.department && p.department._id === deptId);
            setProgrammes(filtered);
        } catch (err) {
            alert('Error fetching programmes');
        }
    };

    const handleDepartmentChange = (e) => {
        const deptId = e.target.value;
        setFormData({...formData, department: deptId, programme: ''});
        fetchProgrammes(deptId);
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            await API.post('/master/block', formData);
            setFormData({ department: '', programme: '', blockName: '' });
            fetchBlocks();
            alert('Block added successfully!');
        } catch (err) {
            alert('Error adding block');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={{ padding: '40px', color: 'white', background: '#0f172a', minHeight: '100vh' }}>
            <h2 style={{ fontSize: '2rem', marginBottom: '30px' }}>Block Master</h2>
            
            <form onSubmit={handleSubmit} style={{ maxWidth: '500px', marginBottom: '40px' }}>
                <div style={{ marginBottom: '15px' }}>
                    <label>Department</label>
                    <select 
                        required
                        value={formData.department}
                        onChange={handleDepartmentChange}
                        style={inputStyle}
                    >
                        <option value="">Select Department</option>
                        {departments.map(dept => (
                            <option key={dept._id} value={dept._id}>{dept.department}</option>
                        ))}
                    </select>
                </div>
                
                <div style={{ marginBottom: '15px' }}>
                    <label>Programme</label>
                    <select 
                        required
                        value={formData.programme}
                        onChange={e => setFormData({...formData, programme: e.target.value})}
                        style={inputStyle}
                    >
                        <option value="">Select Programme</option>
                        {programmes.map(prog => (
                            <option key={prog._id} value={prog._id}>{prog.programme}</option>
                        ))}
                    </select>
                </div>
                
                <div style={{ marginBottom: '15px' }}>
                    <label>Block Name</label>
                    <input 
                        type="text" 
                        required
                        value={formData.blockName}
                        onChange={e => setFormData({...formData, blockName: e.target.value})}
                        style={inputStyle}
                    />
                </div>

                <button type="submit" disabled={loading} style={btnStyle}>
                    {loading ? 'Adding...' : 'Add Block'}
                </button>
            </form>

            <h3>Blocks List</h3>
            <table style={tableStyle}>
                <thead>
                    <tr>
                        <th>Department</th>
                        <th>Programme</th>
                        <th>Block Name</th>
                    </tr>
                </thead>
                <tbody>
                    {blocks.map(block => (
                        <tr key={block._id}>
                            <td>{block.department?.department}</td>
                            <td>{block.programme?.programme}</td>
                            <td>{block.blockName}</td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

const inputStyle = { 
    width: '100%', 
    padding: '10px', 
    marginTop: '5px',
    borderRadius: '5px', 
    border: '1px solid #334155', 
    background: '#1e293b', 
    color: 'white',
    boxSizing: 'border-box'
};

const btnStyle = { 
    padding: '12px 20px', 
    background: 'linear-gradient(to right, #38bdf8, #818cf8)', 
    border: 'none', 
    borderRadius: '5px', 
    color: 'white', 
    fontWeight: 'bold', 
    cursor: 'pointer',
    width: '100%'
};

const tableStyle = {
    width: '100%',
    borderCollapse: 'collapse',
    marginTop: '20px',
    border: '1px solid #334155'
};

export default BlockMaster;
